fn generated_name(p: u32, q: u32, inv: &TorusInvariants, chamber: Chamber) -> CuratedName {
    let family = match chamber {
        Chamber::Intake => {
            if p == q {
                "buleyean-strip"
            } else if q == 1 || p == 1 {
                "waterwheel"
            } else {
                "intake-mill"
            }
        }
        Chamber::Compression => "solomon",
        Chamber::Ignition => "mobius",
        Chamber::Exhaust => "grassmannian",
        Chamber::Interference => "interference",
    };
    let glyph = match chamber {
        Chamber::Intake => "◌",
        Chamber::Compression => "⋈",
        Chamber::Ignition => "☘",
        Chamber::Exhaust => "✺",
        Chamber::Interference => "≋",
    };
    let name_static: &'static str = Box::leak(format!("T({},{})", p, q).into_boxed_str());
    let kind = if inv.is_link { "link" } else { "knot" };
    let notes: &'static str = Box::leak(
        format!(
            "discovered {} (c={}, gcd={}, components={})",
            kind, inv.crossings, inv.gcd_pq, inv.components
        )
        .into_boxed_str(),
    );
    CuratedName {
        name: name_static,
        glyph,
        family,
        notes,
    }
}

// ───────────────────────────────────────────────────────────────────────────
// Scan record + serializable shape
// ───────────────────────────────────────────────────────────────────────────

#[derive(Clone, Debug, Serialize, Deserialize)]
struct TorusInvariants {
    crossings: u32,
    genus: Option<u32>,
    bridge: Option<u32>,
    components: u32,
    gcd_pq: u32,
    is_unknot: bool,
    is_link: bool,
}

#[derive(Clone, Debug, Serialize, Deserialize)]
struct AlgorithmShape {
    shape_id: String,
    key: String, // "p,q"
    p: u32,
    q: u32,
    name: String,
    glyph: String,
    family: String,
    notes: String,
    chamber: String,
    flow_phase: String,
    wallington_dimension: u32,
    invariants: TorusInvariants,
    waterwheel_score: f64,
    planarity_score: f64,
    chirality_score: f64,
    bloom_score: f64,
    bracket_polynomial: Option<String>,
    bracket_span: Option<i64>,
    bracket_span_witness_4q: Option<bool>,
    bule_cost: u32,
    lean_citations: Vec<String>,
    anti_rotation_shape_id: Option<String>,
    curated: bool,
}

#[derive(Clone, Debug)]
struct ScanRecord {
    p: u32,
    q: u32,
    inv: TorusInvariants,
    ww: f64,
    planar: f64,
    chir: f64,
    chamber: Chamber,
    name: CuratedName,
    curated: bool,
    pts: Vec<Vec3>,
}

// ───────────────────────────────────────────────────────────────────────────
// Scan loop
// ───────────────────────────────────────────────────────────────────────────

const P_MIN: u32 = 1;
const P_MAX: u32 = 9;
const Q_MIN: u32 = 1;
const Q_MAX: u32 = 11;

fn scan_one(p: u32, q: u32) -> ScanRecord {
    // segs=80 with cap=max(p,q) gives 80*max(p,q) points: enough for stable
    // PCA + writhe, fast enough to brute force the whole grid in << 60s.
    // R/r = 1.6 / 0.8 — matches knot-viz default (major=1.6, r = tube*4 = 0.8).
    let pts = torus_curve(p, q, 1.6, 0.8, 80);
    let inv = torus_invariants(p, q);
    let ww = waterwheel_score(&pts);
    let planar = planarity_score(&pts);
    let chir = chirality_score(&pts);
    let chamber = assign_chamber(p, q, &inv, ww, planar, chir);
    let (name, curated) = match curated_name(p, q) {
        Some(n) => (n, true),
        None => (generated_name(p, q, &inv, chamber), false),
    };
    ScanRecord {
        p,
        q,
        inv,
        ww,
        planar,
        chir,
        chamber,
        name,
        curated,
        pts,
    }
}

// ───────────────────────────────────────────────────────────────────────────
// Anti-rotation pairing
//
// Each torus knot T(p, q) is right-handed under our sampling convention.
// Its mirror T(p, -q) is the same diagram with reversed crossings (left-
// handed). Our sampler only handles q >= 1, so we synthesize the anti-rotation
// id from the same (p, q) tagged "_mirror" and emit a paired record. Sign of
// chirality_score flips; magnitude preserved; same complexity class.
// ───────────────────────────────────────────────────────────────────────────

fn mirror_record(orig: &ScanRecord) -> Option<ScanRecord> {
    if orig.chir.abs() < 0.05 {
        return None; // achiral — its own mirror, no need to pair.
    }
    // Reflect z to flip handedness: leaves topology and complexity untouched.
    let pts: Vec<Vec3> = orig
        .pts
        .iter()
        .map(|p| Vec3 {
            x: p.x,
            y: p.y,
            z: -p.z,
        })
        .collect();
    let ww = waterwheel_score(&pts);
    let planar = planarity_score(&pts);
    let chir = chirality_score(&pts);
    // Inherit chamber, family, etc., but with mirror suffix on the name.
    let mirror_name_str: &'static str =
        Box::leak(format!("{} (mirror)", orig.name.name).into_boxed_str());
    let mirror_notes_str: &'static str = Box::leak(
        format!(
            "{} — left-handed anti-rotation of T({},{})",
            orig.name.notes, orig.p, orig.q
        )
        .into_boxed_str(),
    );
    let mirror_name = CuratedName {
        name: mirror_name_str,
        glyph: orig.name.glyph,
        family: orig.name.family,
        notes: mirror_notes_str,
    };
    Some(ScanRecord {
        p: orig.p,
        q: orig.q,
        inv: orig.inv.clone(),
        ww,
        planar,
        chir,
        chamber: orig.chamber,
        name: mirror_name,
        curated: false,
        pts,
    })
}

// ───────────────────────────────────────────────────────────────────────────
// Conversion + serialization
// ───────────────────────────────────────────────────────────────────────────

fn record_to_shape(r: &ScanRecord, suffix: Option<&str>) -> AlgorithmShape {
    let shape_id = match suffix {
        Some(s) => format!("T_{}_{}__{}", r.p, r.q, s),
        None => format!("T_{}_{}", r.p, r.q),
    };
    let key = format!("{},{}", r.p, r.q);
    let bracket = if r.p == 2 && r.q >= 1 && r.q <= 30 {
        let lp = kauffman_bracket_t2n(r.q);
        Some(lp)
    } else {
        None
    };
    let bracket_str = bracket.as_ref().map(|lp| lp.to_string_in_a());
    let bracket_span = bracket.as_ref().map(|lp| lp.span());
    let bracket_span_witness = bracket_span.map(|s| s == 4 * r.q as i64);
    let citations: Vec<String> = lean_citation(r.p, r.q)
        .into_iter()
        .map(String::from)
        .collect();
    let bule_cost = r.inv.crossings;
    AlgorithmShape {
        shape_id,
        key,
        p: r.p,
        q: r.q,
        name: r.name.name.to_string(),
        glyph: r.name.glyph.to_string(),
        family: r.name.family.to_string(),
        notes: r.name.notes.to_string(),
        chamber: r.chamber.name().to_string(),
        flow_phase: r.chamber.flow_phase().to_string(),
        wallington_dimension: wallington_dimension(r.p, r.q),
        invariants: r.inv.clone(),
        waterwheel_score: r.ww,
        planarity_score: r.planar,
        chirality_score: r.chir,
        bloom_score: bloom_score(r.ww, r.planar),
        bracket_polynomial: bracket_str,
        bracket_span,
        bracket_span_witness_4q: bracket_span_witness,
        bule_cost,
        lean_citations: citations,
        anti_rotation_shape_id: None,
        curated: r.curated,
    }
}

// ───────────────────────────────────────────────────────────────────────────
// Sanity check the bracket math against the Lean witnesses for T(2, 1..5).
// ───────────────────────────────────────────────────────────────────────────

fn sanity_check_bracket() -> Result<(), String> {
    let expected: &[(u32, &[(i64, i64)])] = &[
        (1, &[(3, -1)]),
        (2, &[(-4, -1), (4, -1)]),
        (3, &[(-7, 1), (-3, -1), (5, -1)]),
        (4, &[(-10, -1), (-6, 1), (-2, -1), (6, -1)]),
        (5, &[(-13, 1), (-9, -1), (-5, 1), (-1, -1), (7, -1)]),
    ];
    for (n, want) in expected {
        let got = kauffman_bracket_t2n(*n);
        let got_v = &got.terms;
        if got_v.as_slice() != *want {
            return Err(format!(
                "Kauffman bracket disagreement at T(2,{}): expected {:?}, got {:?}",
                n, want, got_v
            ));
        }
    }
    Ok(())
}

// ───────────────────────────────────────────────────────────────────────────
// Markdown + JS dictionary emission
// ───────────────────────────────────────────────────────────────────────────

fn render_markdown(shapes: &[AlgorithmShape], records: &BTreeMap<String, ScanRecord>) -> String {
    let mut s = String::new();
    s.push_str("# Algorithm Shape Catalog\n\n");
    s.push_str("Brute-force scan of torus-knot (p, q) parameter space — every shape\n");
    s.push_str("here is a unique computation primitive the aeon FOIL scheduler can\n");
    s.push_str("pick from. Generated by `cargo run --bin algorithm-shapes-scanner`.\n\n");
    s.push_str(&format!(
        "* Scan window: p in [{}, {}], q in [{}, {}]\n",
        P_MIN, P_MAX, Q_MIN, Q_MAX
    ));
    s.push_str(&format!(
        "* Total shapes catalogued: **{}**\n",
        shapes.len()
    ));
    let chambers_present: std::collections::BTreeSet<&str> =
        shapes.iter().map(|s| s.chamber.as_str()).collect();
    s.push_str(&format!(
        "* Wankel chambers covered: **{}** ({})\n",
        chambers_present.len(),
        chambers_present
            .iter()
            .copied()
            .collect::<Vec<_>>()
            .join(", ")
    ));
    let chiral: Vec<&AlgorithmShape> = shapes
        .iter()
        .filter(|s| s.chirality_score.abs() > 0.05)
        .collect();
    s.push_str(&format!(
        "* Chiral shapes (|c| > 0.05): **{}** (anti-rotation paired)\n",
        chiral.len()
    ));
    s.push_str("* Math witnesses: T(2, n) Kauffman bracket cross-checked against ");
    s.push_str("`Gnosis/KnotTheory/TorusKnotChebyshevBracket.lean` for n in 1..5.\n\n");

    s.push_str("## Chirality distribution\n\n");
    let chirs: Vec<f64> = shapes.iter().map(|s| s.chirality_score).collect();
    let chir_min = chirs.iter().cloned().fold(f64::INFINITY, f64::min);
    let chir_max = chirs.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
    let chir_mean = if chirs.is_empty() {
        0.0
    } else {
        chirs.iter().sum::<f64>() / chirs.len() as f64
    };
    s.push_str(&format!(
        "min={:.3}  max={:.3}  mean={:.3}\n\n",
        chir_min, chir_max, chir_mean
    ));

    // One section per shape, ordered by chamber then crossings then (p, q).
    let mut ordered: Vec<&AlgorithmShape> = shapes.iter().collect();
    ordered.sort_by(|a, b| {
        a.chamber
            .cmp(&b.chamber)
            .then(a.invariants.crossings.cmp(&b.invariants.crossings))
            .then(a.p.cmp(&b.p))
            .then(a.q.cmp(&b.q))
            .then(a.shape_id.cmp(&b.shape_id))
    });

    let mut current_chamber = String::new();
    for sh in ordered {
        if sh.chamber != current_chamber {
            current_chamber = sh.chamber.clone();
            s.push_str(&format!(
                "\n---\n\n## Chamber: {} (flow phase: {})\n",
                current_chamber, sh.flow_phase
            ));
        }
        s.push_str(&format!(
            "\n### {} {}  —  `{}`\n",
            sh.glyph, sh.name, sh.shape_id
        ));
        s.push_str(&format!(
            "* (p, q) = ({}, {})  family = {}  curated = {}\n",
            sh.p, sh.q, sh.family, sh.curated
        ));
        s.push_str(&format!(
            "* crossings = {}  genus = {}  components = {}  gcd = {}\n",
            sh.invariants.crossings,
            sh.invariants
                .genus
                .map_or("-".to_string(), |v| v.to_string()),
            sh.invariants.components,
            sh.invariants.gcd_pq,
        ));
        s.push_str(&format!(
            "* wallington_dimension = {}  bule_cost = {}\n",
            sh.wallington_dimension, sh.bule_cost
        ));
        s.push_str(&format!(
            "* scores: waterwheel = {:.3}  planarity = {:.3}  chirality = {:+.3}  bloom = {:.3}\n",
            sh.waterwheel_score, sh.planarity_score, sh.chirality_score, sh.bloom_score
        ));
        if let Some(b) = &sh.bracket_polynomial {
            let witness = sh
                .bracket_span_witness_4q
                .map(|w| if w { "ok 4q" } else { "FAIL" })
                .unwrap_or("-");
            s.push_str(&format!(
                "* bracket <T(2,{})> = {}    span = {}  ({})\n",
                sh.q,
                b,
                sh.bracket_span.unwrap_or(0),
                witness
            ));
        }
        s.push_str(&format!("* notes: {}\n", sh.notes));
        if let Some(anti) = &sh.anti_rotation_shape_id {
            s.push_str(&format!("* anti-rotation: `{}`\n", anti));
        }
        if !sh.lean_citations.is_empty() {
            s.push_str("* lean witnesses:\n");
            for c in &sh.lean_citations {
                s.push_str(&format!("  * `{}`\n", c));
            }
        }
        // ASCII XY projection (only emit for right-handed copy; mirrors are
        // visually a flipped z which doesn't show in xy anyway).
        if let Some(rec) = records.get(&sh.shape_id) {
            s.push_str("\n```\n");
            s.push_str(&ascii_xy(&rec.pts, 48, 22));
            s.push_str("```\n");
        }
    }
    s
}

fn render_js_dict(shapes: &[AlgorithmShape]) -> String {
    // Drop-in replacement for KNOT_MOMENTS in knot-viz.html. Keyed by "p,q"
    // (matching the original lookup `KNOT_MOMENTS[`${pi},${qi}`]`). Mirror /
    // anti-rotation duplicates collapse to the right-handed entry (same key).
    let mut by_key: BTreeMap<String, &AlgorithmShape> = BTreeMap::new();
    for sh in shapes {
        // Prefer the curated, right-handed (no "mirror" suffix) entry on
        // collision so we don't shadow Solomon's link with its mirror copy.
        let entry = by_key.entry(sh.key.clone()).or_insert(sh);
        if !sh.shape_id.contains("mirror") && (sh.curated && !entry.curated) {
            *entry = sh;
        }
        if !sh.shape_id.contains("mirror") && entry.shape_id.contains("mirror") {
            *entry = sh;
        }
    }
    let mut s = String::new();
    s.push_str("// algorithm_shapes_dict.js — generated by\n");
    s.push_str("//   open-source/gnosis/distributed-inference\n");
    s.push_str("//     cargo run --bin algorithm-shapes-scanner\n");
    s.push_str("//\n");
    s.push_str("// Drop-in replacement for the hand-curated KNOT_MOMENTS dictionary in\n");
    s.push_str("// open-source/aeon-3d/src/knot-viz.html. Keyed by `${round(p)},${round(q)}`.\n");
    s.push_str("// Geometric scores + Wankel chamber + Wallington dimension are appended\n");
    s.push_str("// to each entry on top of the original {name, glyph, family, chamber, notes}\n");
    s.push_str("// schema so the existing JS detectMoment() path keeps working.\n\n");
    s.push_str("export const KNOT_MOMENTS = {\n");
    for (k, sh) in &by_key {
        let anti = sh.chirality_score.abs() > 0.05;
        s.push_str(&format!(
            "  '{}': {{ name: {}, glyph: {}, family: {}, chamber: {}, anti: {}, notes: {}, ",
            k,
            js_str(&sh.name),
            js_str(&sh.glyph),
            js_str(&sh.family),
            js_str(&sh.chamber),
            anti,
            js_str(&sh.notes),
        ));
        s.push_str(&format!(
            "p: {}, q: {}, wallingtonDimension: {}, buleCost: {}, ",
            sh.p, sh.q, sh.wallington_dimension, sh.bule_cost
        ));
        s.push_str(&format!(
            "scores: {{ waterwheel: {:.4}, planarity: {:.4}, chirality: {:.4}, bloom: {:.4} }}, ",
            sh.waterwheel_score, sh.planarity_score, sh.chirality_score, sh.bloom_score
        ));
        s.push_str(&format!(
            "invariants: {{ crossings: {}, genus: {}, components: {}, gcd: {} }}, ",
            sh.invariants.crossings,
            sh.invariants
                .genus
                .map_or("null".to_string(), |v| v.to_string()),
            sh.invariants.components,
            sh.invariants.gcd_pq,
        ));
        s.push_str(&format!(
            "antiRotationShapeId: {}, leanCitations: [{}] }},\n",
            sh.anti_rotation_shape_id
                .as_ref()
                .map_or("null".to_string(), |id| js_str(id)),
            sh.lean_citations
                .iter()
                .map(|c| js_str(c))
                .collect::<Vec<_>>()
                .join(", "),
        ));
    }
    s.push_str("};\n\n");
    s.push_str("export default KNOT_MOMENTS;\n");
    s
}

fn js_str(s: &str) -> String {
    // Single-quote JS string literal with backslash-escaping. Mirrors the
    // original KNOT_MOMENTS style (which uses single quotes throughout).
    let mut out = String::with_capacity(s.len() + 2);
    out.push('\'');
    for ch in s.chars() {
        match ch {
            '\\' => out.push_str("\\\\"),
            '\'' => out.push_str("\\'"),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            _ => out.push(ch),
        }
    }
    out.push('\'');
    out
}

// ───────────────────────────────────────────────────────────────────────────
// main
// ───────────────────────────────────────────────────────────────────────────

fn main() -> Result<(), String> {
    let t0 = std::time::Instant::now();

    // 1. Sanity-check Kauffman bracket math against Lean witnesses first;
    //    a math disagreement means the rest of the run is suspect.
    sanity_check_bracket()?;
    eprintln!("[scanner] Kauffman bracket parity check vs Lean T(2,1..5): OK");

    // 2. Build the scan grid and process in parallel via rayon.
    let mut grid: Vec<(u32, u32)> = Vec::new();
    for p in P_MIN..=P_MAX {
        for q in Q_MIN..=Q_MAX {
            grid.push((p, q));
        }
    }
    let records: Vec<ScanRecord> = grid.par_iter().map(|&(p, q)| scan_one(p, q)).collect();
    eprintln!(
        "[scanner] scanned {} (p, q) cells in {:.2}s",
        records.len(),
        t0.elapsed().as_secs_f64()
    );

    // 3. Synthesize mirror (anti-rotation) records for chiral shapes. The
    //    is_mirror tag rides with the record itself so suffix assignment is
    //    unambiguous downstream.
    let mut all_records: Vec<(ScanRecord, bool)> = Vec::new();
    for r in &records {
        all_records.push((r.clone(), false));
        if let Some(m) = mirror_record(r) {
            all_records.push((m, true));
        }
    }

    // 4. Convert to serializable shapes. Mirror entries get a "_mirror"
    //    suffix on shape_id so they don't collide with the right-handed copy.
    let mut shapes: Vec<AlgorithmShape> = Vec::with_capacity(all_records.len());
    let mut record_lookup: BTreeMap<String, ScanRecord> = BTreeMap::new();
    for (r, is_mirror) in &all_records {
        let suffix = if *is_mirror { Some("mirror") } else { None };
        let sh = record_to_shape(r, suffix);
        record_lookup.insert(sh.shape_id.clone(), r.clone());
        shapes.push(sh);
    }

    // 5. Pair anti-rotations: for each chiral shape, find sibling with same
    //    (p, q) and opposite-sign chirality at the same complexity.
    let mut by_pq: BTreeMap<(u32, u32), Vec<usize>> = BTreeMap::new();
    for (i, sh) in shapes.iter().enumerate() {
        by_pq.entry((sh.p, sh.q)).or_default().push(i);
    }
    for indices in by_pq.values() {
        for &i in indices {
            let chir_i = shapes[i].chirality_score;
            if chir_i.abs() < 0.05 {
                continue;
            }
            // find the sibling whose chirality has opposite sign
            for &j in indices {
                if j == i {
                    continue;
                }
                let chir_j = shapes[j].chirality_score;
                if chir_i.signum() != chir_j.signum() && chir_j.abs() > 0.05 {
                    let sibling_id = shapes[j].shape_id.clone();
                    shapes[i].anti_rotation_shape_id = Some(sibling_id);
                    break;
                }
            }
        }
    }

    // 6. Emit artifacts.
    let mut out_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    out_dir.push("target");
    out_dir.push("algorithm-shapes");
    fs::create_dir_all(&out_dir).map_err(|e| format!("mkdir target: {}", e))?;

    let json_path = out_dir.join("algorithm_shapes.json");
    let md_path = out_dir.join("algorithm_shapes_report.md");
    let js_path = out_dir.join("algorithm_shapes_dict.js");

    let json =
        serde_json::to_string_pretty(&shapes).map_err(|e| format!("serialize json: {}", e))?;
    fs::write(&json_path, json).map_err(|e| format!("write json: {}", e))?;
    let md = render_markdown(&shapes, &record_lookup);
    fs::write(&md_path, md).map_err(|e| format!("write md: {}", e))?;
    let js = render_js_dict(&shapes);
    fs::write(&js_path, js).map_err(|e| format!("write js: {}", e))?;

    let chiral_count = shapes
        .iter()
        .filter(|s| s.chirality_score.abs() > 0.05)
        .count();
    let paired_count = shapes
        .iter()
        .filter(|s| s.anti_rotation_shape_id.is_some())
        .count();
    let chambers: std::collections::BTreeSet<&str> =
        shapes.iter().map(|s| s.chamber.as_str()).collect();

    eprintln!(
        "[scanner] wrote {} shapes ({} chiral, {} anti-rotation-paired) across {} chambers",
        shapes.len(),
        chiral_count,
        paired_count,
        chambers.len()
    );
    eprintln!("[scanner] -> {}", json_path.display());
    eprintln!("[scanner] -> {}", md_path.display());
    eprintln!("[scanner] -> {}", js_path.display());
    eprintln!(
        "[scanner] total wall time: {:.2}s",
        t0.elapsed().as_secs_f64()
    );

    Ok(())
}
